+    let (br, bi) = rhs;
+    match primitive {
+        Primitive::Add => Ok((ar + br, ai + bi)),
+        Primitive::Sub => Ok((ar - br, ai - bi)),
+        Primitive::Mul => Ok((ar * br - ai * bi, ar * bi + ai * br)),
+        Primitive::Div => {
